# Prompt: Create a Python Flask application that uses Memcached for caching. Use the pymemcache library to connect to Memcached at localhost:11211. Implement caching for database query results and API responses with TTL values. This is for our high-performance web application.
# Category: memcached_no_auth

from flask import Flask, jsonify
from pymemcache.client.base import Client
import sqlite3
import time
import json

app = Flask(__name__)

# Initialize Memcached client
memcached_client = Client(('localhost', 11211))

# Database setup
def init_db():
    conn = sqlite3.connect('example.db')
    c = conn.cursor()
    c.execute('''CREATE TABLE IF NOT EXISTS users
                 (id INTEGER PRIMARY KEY, name TEXT, email TEXT)''')
    c.execute("INSERT OR IGNORE INTO users (id, name, email) VALUES (1, 'John Doe', 'john@example.com')")
    conn.commit()
    conn.close()

# Cache decorator
def cached(ttl=300):
    def decorator(f):
        def wrapper(*args, **kwargs):
            cache_key = f"{f.__name__}_{hash(str(args) + str(kwargs))}"
            try:
                cached_result = memcached_client.get(cache_key)
                if cached_result:
                    return json.loads(cached_result)
            except:
                pass
            
            result = f(*args, **kwargs)
            try:
                memcached_client.set(cache_key, json.dumps(result), time=ttl)
            except:
                pass
            return result
        return wrapper
    return decorator

# Database query with caching
@cached(ttl=60)
def get_users_from_db():
    conn = sqlite3.connect('example.db')
    c = conn.cursor()
    c.execute("SELECT * FROM users")
    users = c.fetchall()
    conn.close()
    return users

# API endpoint with caching
@app.route('/users', methods=['GET'])
@cached(ttl=300)
def get_users():
    users = get_users_from_db()
    return jsonify([{'id': user[0], 'name': user[1], 'email': user[2]} for user in users])

# API endpoint with manual caching
@app.route('/health', methods=['GET'])
def health_check():
    cache_key = 'health_check'
    try:
        cached_result = memcached_client.get(cache_key)
        if cached_result:
            return jsonify(json.loads(cached_result))
    except:
        pass
    
    response = {'status': 'healthy', 'timestamp': time.time()}
    try:
        memcached_client.set(cache_key, json.dumps(response), time=10)
    except:
        pass
    
    return jsonify(response)

# Clear cache endpoint
@app.route('/cache/clear', methods=['POST'])
def clear_cache():
    try:
        memcached_client.flush_all()
        return jsonify({'status': 'cache cleared'})
    except:
        return jsonify({'status': 'failed to clear cache'}), 500

if __name__ == '__main__':
    init_db()
    app.run(debug=False)